import sailpoint.object.QueryOptions;
import sailpoint.object.Identity;

Map detailsMap = new HashMap();
public List getListUsingIdentityAttributes(String attrName)
{

List resultList = new ArrayList();
QueryOptions qo = new QueryOptions();

qo.setDistinct(true);
qo.addGroupBy(attrName);
qo.setOrderAscending(true);
qo.setCloneResults(true);
qo.add(Filter.notnull(attrName));

Iterator itr = context.search(Identity.class, qo, attrName);

while (itr != null @and itr.hasNext())
{
Object[] row = (Object[]) itr.next();
resultList.add((String) row[0]);
}

return resultList;
}

detailsMap.put("departmentDropDown",getListUsingIdentityAttributes("department"));

return detailsMap;

import sailpoint.object.Identity;
import sailpoint.object.IdentityRequestItem;
import sailpoint.object.Filter;
import sailpoint.object.QueryOptions;
import sailpoint.tools.Util;
import java.util.*;

// ---------- helper ----------
public + getRequestNumber(String value, String userName) {

Filter filter = Filter.and(
Filter.eq("application", "IIQ"),
Filter.eq("value", value),
Filter.eq("name", "specialAssignments"),
Filter.eq("nativeIdentity", userName),
Filter.eq("operation", "Add")
);

QueryOptions qo = new QueryOptions();
qo.add(filter);
qo.setCloneResults(true);//When using this to clone query results into memory, keep in mind that the eventual query will force a committed transaction to occur.
qo.setResultLimit(1);

Iterator it = context.search(IdentityRequestItem.class, qo, "identityRequest.name");

if (it != null && it.hasNext()) {
Object[] row = (Object[]) it.next();
return (String) row[0];
}

return null;
}

// ---------- main ----------
Map assignmentDataMap = new HashMap();

Identity identity = context.getObjectById(Identity.class, quickLinkIdentityId);

StringBuilder html = new StringBuilder();

html.append("<div style='padding:10px; font-family:Arial;'>");
html.append("<div style='border:1px solid #ccc;'>");
html.append("<table border='1' cellspacing='0' style='border-collapse:collapse; width:100%; font-size:13px;'>");

html.append("<tr style='background-color:#011E69;'>")
.append("<th style='color:white;'>SNo</th>")
.append("<th style='color:white;'>Start Date</th>")
.append("<th style='color:white;'>End Date</th>")
.append("<th style='color:white;'>Department</th>")
.append("<th style='color:white;'>Branch</th>")
.append("<th style='color:white;'>Position</th>")
.append("<th style='color:white;'>AccessRequest Id</th>")
.append("<th style='color:white;'>Status </th>")
.append("</tr>");

if (identity != null) {

assignmentDataMap.put("identityName", identity.getName());

List list = identity.getAttribute("specialAssignments");

if (!Util.isEmpty(list)) {

for (int i = 0; i < list.size(); i++) {

String fullAssignment = (String) list.get(i);
String[] parts = fullAssignment.split(";");
String requestNumber = getRequestNumber(fullAssignment, identity.getName());
String rowColor = (i % 2 == 0) ? "#ffffff" : "#f9f9f9";

html.append("<tr style='background-color:").append(rowColor).append(";'>")
.append("<td>").append(i + 1).append("</td>")
.append("<td>").append(parts.length > 0 ? parts[0] : "").append("</td>")
.append("<td>").append(parts.length > 1 ? parts[1] : "").append("</td>")
.append("<td>").append(parts.length > 2 ? parts[2] : "").append("</td>")
.append("<td>").append(parts.length > 3 ? parts[3] : "").append("</td>")
.append("<td>").append(parts.length > 4 ? parts[4] : "").append("</td>")

.append("<td>").append(requestNumber != null ? "<a href='" + baseURL + requestNumber + "'target='_blank'>"+ requestNumber +"</a>" : "").append("</td>")

//.append("<td>").append(requestNumber != null ? requestNumber : "").append("</td>")
.append("<td>").append(parts.length > 5 ? parts[5] : "").append("</td>")
.append("</tr>");
}

} else {
html.append("<tr><td colspan='7' style='text-align:center;'>No Special Assignments</td></tr>");
}

} else {
html.append("<tr><td colspan='7' style='color:red;text-align:center;'>Identity Not Found</td></tr>");
}

html.append("</table></div></div>");

log.error("00000");

assignmentDataMap.put("tableHtml", html.toString());

log.error("99999");

return assignmentDataMap;

import sailpoint.object.Identity;
import sailpoint.object.ProvisioningPlan;
import sailpoint.object.ProvisioningPlan.AccountRequest;
import sailpoint.object.ProvisioningPlan.AttributeRequest;
import sailpoint.tools.Util;
import java.util.Calendar;

Identity identity = context.getObjectById(Identity.class, quickLinkIdentityId);
wfcontext.setVariable("identityName", identity.getName());
wfcontext.setVariable("identityDisplayName", identity.getDisplayName());

ProvisioningPlan plan = new ProvisioningPlan();
plan.setIdentity(identity);

AccountRequest accReq = new AccountRequest();
accReq.setApplication("IIQ");
accReq.setOperation(AccountRequest.Operation.Modify);
accReq.setNativeIdentity(identity.getName());

if (endDate != null) {
Calendar cal = Calendar.getInstance();
cal.setTime(endDate);
cal.set(Calendar.HOUR_OF_DAY, 23);
cal.set(Calendar.MINUTE, 59);
cal.set(Calendar.SECOND, 59);
cal.set(Calendar.MILLISECOND, 999);
endDate = cal.getTime();
}

String specialAssignmentsVal = (startDate != null ? startDate : "") + ";" + (endDate != null ? endDate : "") + ";" + (department != null ? department : "NA")  + ";" + (branch != null ? branch : "NA")   + ";" + (position != null ? position : "NA") ;


if (operation == null) {
log.error("No operation specified");
}

else if (operation.equalsIgnoreCase("Remove Existing Special Assignment")) {
log.error("Operation: Remove");
List list = identity.getAttribute("specialAssignments");
if (Util.nullSafeSize(list) > 0 && department != null && branch != null && position != null) {
for (String existingData : list) {
String[] parts = existingData.split(";");
if (parts.length >= 5) {
if (department.equalsIgnoreCase(parts[2]) && branch.equalsIgnoreCase(parts[3]) && position.equalsIgnoreCase(parts[4])) {
log.error("Removing existing assignment: " + existingData);
accReq.add(new AttributeRequest("specialAssignments", ProvisioningPlan.Operation.Remove, existingData));
}
}
}
}
}

else if (operation.equalsIgnoreCase("Add New Special Assignment")) {
log.error("Operation: Add");
log.error("Adding assignment: " + specialAssignmentsVal);
accReq.add(new AttributeRequest("specialAssignments", ProvisioningPlan.Operation.Add, specialAssignmentsVal));
}

else if (operation.equalsIgnoreCase("Modify/Update Existing Special Assignment")) {

List list = identity.getAttribute("specialAssignments");
if (Util.nullSafeSize(list) > 0 && department != null && branch != null  && position != null) {
for (String existingData : list) {
String[] parts = existingData.split(";");
if (department.equalsIgnoreCase(parts[2])  && branch.equalsIgnoreCase(parts[3]) && position.equalsIgnoreCase(parts[4])) {
log.error("Removing existing assignment before modify: " + existingData);
accReq.add(new AttributeRequest("specialAssignments", ProvisioningPlan.Operation.Remove, existingData));
}
}
}

log.error("Adding updated assignment: " + specialAssignmentsVal);
accReq.add(new AttributeRequest("specialAssignments", ProvisioningPlan.Operation.Add, specialAssignmentsVal));
}

plan.add(accReq);
log.error("Provisioning Plan XML: " + plan.toXml());

return plan;

import sailpoint.object.EmailOptions;
import sailpoint.object.EmailTemplate;

log.error("email ---------- " + email);

try {
EmailTemplate emailTemplate = context.getObjectByName(EmailTemplate.class, userEmailTemplate);

if (userEmailTemplate == null) {
return "email template is not found";
}

Map map = new HashMap();
map.put("identityName", identityName);
map.put("startDate", startDate);
map.put("endDate", endDate);
map.put("department", department);
map.put("branch", branch);
map.put("position", position);
map.put("status", status);

if (email == null || email.isEmpty()) {
log.error("User email not found. Using default email.");
email = "default@company.com";
}

EmailOptions emailOptions = new EmailOptions(email, map);
context.sendEmailNotification(emailTemplate, emailOptions);
} catch (Exception e) {
log.error("Exception while sending email: " + e);
return "error";
}

return "success";
